const items = $input.all();

  if (items.length === 1 && (items[0].json.noResults || items[0].json.noNewGrants)) {
    return items;
  }

  function extractDate(grant) {
    const candidates = [
      grant.closeDate,
      grant.deadline,
      grant.dueDate,
      grant.due_date,
      grant.endDate,
      grant.end_date,
      grant.applicationDeadline,
      grant.application_deadline,
    ];

    for (const val of candidates) {
      if (!val || typeof val !== 'string') continue;
      const parsed = new Date(val);
      if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
        return parsed;
      }
    }

    if (grant.description) {
      const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
      if (match) {
        const parsed = new Date(match[0]);
        if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
          return parsed;
        }
      }
    }

    return null;
  }

  const withDeadline = [];
  const noDeadline = [];

  for (const item of items) {
    const date = extractDate(item.json);
    if (date) {
      item._sortDate = date;
      withDeadline.push(item);
    } else {
      noDeadline.push(item);
    }
  }

  withDeadline.sort((a, b) => a._sortDate - b._sortDate);

  const combined = [...withDeadline, ...noDeadline];
  return combined.map(item => ({ json: item.json }));

